import{_ as a,o as s,c as l,a2 as t}from"./chunks/framework.BflysNKA.js";const C=JSON.parse('{"title":"进阶技巧","description":"","frontmatter":{},"headers":[],"relativePath":"support/advanced.md","filePath":"support/advanced.md","lastUpdated":1778577020000}'),e={name:"support/advanced.md"};function n(h,i,p,d,r,o){return s(),l("div",null,[...i[0]||(i[0]=[t(`<h1 id="进阶技巧" tabindex="-1">进阶技巧 <a class="header-anchor" href="#进阶技巧" aria-label="Permalink to &quot;进阶技巧&quot;">​</a></h1><p>日常使用中，成本、速度和稳定性通常会一起出现。基础接入已经稳定后，再按下面这些思路继续优化更合适。</p><h2 id="什么时候该看这页" tabindex="-1">什么时候该看这页 <a class="header-anchor" href="#什么时候该看这页" aria-label="Permalink to &quot;什么时候该看这页&quot;">​</a></h2><ul><li>基础接入已经完成</li><li>你开始在意成本、速度和稳定性</li><li>你准备把多工具、多设备配置管理起来</li></ul><h2 id="常见思路" tabindex="-1">常见思路 <a class="header-anchor" href="#常见思路" aria-label="Permalink to &quot;常见思路&quot;">​</a></h2><h3 id="key-分层" tabindex="-1">Key 分层 <a class="header-anchor" href="#key-分层" aria-label="Permalink to &quot;Key 分层&quot;">​</a></h3><p>按设备、按工具、按项目拆开建 Key，比一把通用 Key 更好管。</p><p>这样做不只是为了“看着整齐”，而是为了三个实际效果：</p><ul><li>日志里能一眼看出到底是谁在消耗</li><li>某一台设备泄露时，只需要停掉对应 Key</li><li>你给团队成员或远端服务开权限时，不会牵连自己本机的所有工具</li></ul><p>第一次从“一把全能 Key”拆分出去时，最稳的顺序通常是：</p><ol><li>先保留一把主力 Key</li><li>再单独拆一把桌面客户端 Key</li><li>再单独拆一把 CLI 或服务器 Key</li></ol><p>不要一口气拆十几把。<br> 先拆出最常用、最容易混用的两三把，日志和排障效果就会明显好很多。</p><h3 id="模型分工" tabindex="-1">模型分工 <a class="header-anchor" href="#模型分工" aria-label="Permalink to &quot;模型分工&quot;">​</a></h3><ul><li>轻量模型跑日常对话</li><li>强模型留给复杂分析和大任务</li><li>桌面端和 CLI 分开配置更清楚</li></ul><p>不少工具本身就支持“主模型 + 轻量模型”双配置，例如 OpenCode 的 <code>model</code> 和 <code>small_model</code>。把轻任务交给轻量模型，通常比一把强模型从头跑到尾更省，也更稳。</p><p>第一次做模型分工时，可以直接按用途拆：</p><table tabindex="0"><thead><tr><th>用途</th><th>更合适的模型</th></tr></thead><tbody><tr><td>发一句“你好”测试链路</td><td>轻量模型</td></tr><tr><td>日常问答、翻译、总结</td><td>轻量模型或中档模型</td></tr><tr><td>代码重构、长文分析、大仓库阅读</td><td>强模型</td></tr><tr><td>自动化脚本、批量调用</td><td>轻量模型或低成本模型</td></tr></tbody></table><h3 id="上下文控制" tabindex="-1">上下文控制 <a class="header-anchor" href="#上下文控制" aria-label="Permalink to &quot;上下文控制&quot;">​</a></h3><p>模型变慢、费用变高，很多时候不是接口问题，而是上下文太大。</p><p>一旦你开始怀疑“是不是网关慢”，先回想最近是不是把整个仓库、超长日志或大量截图一起丢给了模型。很多所谓的慢，其实是任务规模已经远超当前问题本身。</p><p>一个简单判断方式：</p><ul><li>问题只和 1-2 个文件有关，就不要把整个仓库一起塞进去</li><li>只是确认配置有没有生效，就不要附带几十屏运行日志</li><li>只是定位模型能不能返回，就先发最短测试消息</li></ul><h3 id="留一把备用-key" tabindex="-1">留一把备用 Key <a class="header-anchor" href="#留一把备用-key" aria-label="Permalink to &quot;留一把备用 Key&quot;">​</a></h3><p>主用 Key 出问题时，可以立刻切换，少中断。 备用 Key 平时不要写入公开脚本，也不要和主力 Key 共用同一份配置文件。</p><p>备用 Key 更适合做这些事：</p><ul><li>主力 Key 临时被禁用时快速切换</li><li>先交叉验证“问题是不是出在这把 Key 上”</li><li>紧急联调时短时替代主力环境</li></ul><p>不适合：</p><ul><li>长期和主力 Key 混用</li><li>写进共享脚本或群文件</li><li>不设额度就长期闲置</li></ul><h3 id="固定一套最小测试" tabindex="-1">固定一套最小测试 <a class="header-anchor" href="#固定一套最小测试" aria-label="Permalink to &quot;固定一套最小测试&quot;">​</a></h3><p>每次怀疑工具配置时，先跑最小 curl：</p><p>先把 <code>MODEL</code> 换成模型广场里复制的轻量模型名：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">MODEL</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;替换成模型广场里的轻量模型名&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> POST</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> https://xiaolan1.cn/v1/chat/completions</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;Authorization: Bearer 你的Key&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;{</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">model</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">$MODEL</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">messages</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">:[{</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">role</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">user</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">content</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">ping</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">}]}&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>curl 正常，问题就在本地工具。curl 不正常，再看 Key、余额、模型和网络。</p><p>只要 curl 正常，后续就别继续盲改充值、分组或模型权限，而应该回到你正在使用的具体工具页面查配置。</p><p>固定一套最小测试的意义在于：<br> 以后每次换模型、换工具、换网络，都能先用同一组最小请求判断“基础链路是不是还活着”。</p><h3 id="控制上下文" tabindex="-1">控制上下文 <a class="header-anchor" href="#控制上下文" aria-label="Permalink to &quot;控制上下文&quot;">​</a></h3><p>AI 编程工具很容易把整个仓库塞给模型。上下文越大：</p><ul><li>响应越慢</li><li>消耗越高</li><li>失败概率越高</li></ul><p>优先提供相关文件。大型改造拆成多个小任务。 CLI 工具处理大仓库时，先让模型读取目录结构，再逐步提供相关文件。</p><h3 id="配置文件比临时命令更稳" tabindex="-1">配置文件比临时命令更稳 <a class="header-anchor" href="#配置文件比临时命令更稳" aria-label="Permalink to &quot;配置文件比临时命令更稳&quot;">​</a></h3><p>当你开始同时使用多个工具时，尽量把长期配置写回各自的正式位置：</p><ul><li>Claude Code：环境变量或对应配置文件</li><li>Codex：<code>config.toml</code> / <code>小蓝中转站_API_KEY</code></li><li>OpenCode：<code>opencode.json</code> / <code>opencode.jsonc</code></li><li>OpenClaw：<code>openclaw.yaml</code></li><li>Gemini CLI：<code>~/.gemini/settings.json</code> 或项目内 <code>.gemini/settings.json</code></li></ul><p>临时导出一两个变量适合排障，但不适合长期维护。正式配置写回去以后，换终端、重启机器或切项目时更不容易丢。</p><p>改了环境变量却总觉得“不稳定”“怎么有时生效有时不生效”时，优先检查是不是：</p><ul><li>旧终端窗口还没关</li><li>当前项目目录里还有一份项目级配置覆盖默认值</li><li>桌面客户端当前会话还停留在旧服务商或旧模型</li></ul><h3 id="先固定一条主工作流" tabindex="-1">先固定一条主工作流 <a class="header-anchor" href="#先固定一条主工作流" aria-label="Permalink to &quot;先固定一条主工作流&quot;">​</a></h3><p>很多“越配越乱”的问题，不是工具不够，而是同时装太多、同时改太多。</p><p>更稳的做法通常是：</p><ol><li>先选一个主力客户端</li><li>先固定一把主力 Key</li><li>先固定一个轻量模型和一个主力模型</li><li>这条链路稳定以后，再扩展第二个工具</li></ol><p>这样做的好处是，出了问题时你知道自己最近只改了哪一层。</p><p>什么时候适合开始扩展第二个工具：</p><ul><li>第一条主链路已经连续几天稳定可用</li><li>你已经知道当前主力模型、主力 Key 和主力配置放在哪里</li><li>你已经能独立判断问题大概卡在安装层、配置层还是模型层</li></ul><p>如果这些还没稳，就先不要急着装第五个工具。</p><h2 id="目前建议" tabindex="-1">目前建议 <a class="header-anchor" href="#目前建议" aria-label="Permalink to &quot;目前建议&quot;">​</a></h2><p>先把最常用的那一条工作流跑顺：</p><ul><li>一把主力 Key</li><li>一个主力工具</li><li>一套稳定模型</li></ul><p>稳定后，再扩展到多工具和多设备。</p><p>还处在“今天能用、明天又乱”的状态时，先不要继续优化成本、切模型或折腾多人模板。<br> 先把最常用的一条链路压到稳定，再谈进阶，收益会更大。</p><h2 id="多工具配置建议" tabindex="-1">多工具配置建议 <a class="header-anchor" href="#多工具配置建议" aria-label="Permalink to &quot;多工具配置建议&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工具</th><th>Key 命名</th><th>模型建议</th></tr></thead><tbody><tr><td>Cherry Studio</td><td><code>Desktop-Cherry</code></td><td>聊天模型 + 轻量模型</td></tr><tr><td>Claude Code</td><td><code>CLI-Claude</code></td><td>代码能力强的模型</td></tr><tr><td>Codex</td><td><code>CLI-Codex</code></td><td>Responses 兼容模型</td></tr><tr><td>Gemini CLI</td><td><code>CLI-Gemini</code></td><td>Gemini / 长上下文模型</td></tr></tbody></table><p>命名一致后，日志里能直接看出是谁在消耗。</p>`,61)])])}const c=a(e,[["render",n]]);export{C as __pageData,c as default};
